module RefModule(
    input a,
    input b,
    input clk,       // Added clk input
    output reg sum,
    output reg cout
);reg unused_s1, c1;

always @ (a or b) begin
    unused_s1 = a ^ b;
    c1 = a & b;
end

always @ (posedge clk) begin
    sum <= unused_s1;
    cout <= c1;
end

endmodule
